scripts.install-local:
mkdir -p .opencode/plugins && cat > .opencode/plugins/skills.ts <<'EOF'
import { SkillsPlugin } from "../../src/plugin.ts";
export default {
  id: "opencode-agent-skills-md",
  server: SkillsPlugin,
};
EOF
bun -e "import {readFileSync,writeFileSync} from 'fs'; const p='.opencode/opencode.json'; const c=JSON.parse(readFileSync(p,'utf-8')); const e='./.opencode/plugins/skills.ts'; c.plugin=Array.isArray(c.plugin)?c.plugin:[]; if(!c.plugin.includes(e))c.plugin.push(e); writeFileSync(p,JSON.stringify(c,null,2)+'\n')"
